# Homebrew formula for Nesbot CLI
# Generated by scripts/generate-formula.sh — do not edit manually
#
# Install: brew install NesloTechnologies/nesbot/nesbot
# Upgrade: brew upgrade nesbot

class Nesbot < Formula
  desc "Deterministic, policy-driven engineering automation CLI"
  homepage "https://github.com/NesloTechnologies/nesbot"
  url "https://github.com/NesloTechnologies/homebrew-nesbot/releases/download/v1.41.0/nesbot-1.41.0-darwin-arm64.tar.gz"
  sha256 "aa258f5c0ed88f4d50d7146b7e77fb010a9b32643ed41b930ebe2c662e049f17"
  version "1.41.0"
  license "MIT"

  def install
    libexec.install Dir["*"]

    # Create a wrapper script that invokes the CLI via the system node
    # Requires Node.js >= 18 (nvm, brew node, or system install)
    (bin/"nesbot").write <<~EOS
      #!/usr/bin/env bash
      exec node "#{libexec}/bin/nesbot.js" "$@"
    EOS
  end

  # No test do block — Homebrew uses PTY to spawn the test subprocess;
  # PTY allocation fails on macOS Sequoia sandbox ("can't get Master/Slave
  # device") regardless of what the test does. Correctness is verified by
  # the release artifact checksum + scripts/verify-release.sh.
end
